    cats = b.get('categories')
    if cats is None:
        cat_list = []
    elif isinstance(cats, list):
        cat_list = cats
    else:
        cat_list = [c.strip() for c in str(cats).split(',') if c.strip()]
    for c in cat_list:
        meta_rows.append({'business_ref': bref, 'category': c})

meta_df = pd.DataFrame(meta_rows)
